def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 50.0
        if usage_ratio > 5:
            priority += 5000 * np.log1p(usage_ratio) - 100 * np.exp(-capacity)
            if capacity > 10:
                for a in range(3, 8):
                    priority += (np.sin(capacity/a) + np.cos(usage_ratio*a)) * 100 / a
            else:
                for b in range(1, 5):
                    priority -= 40 / (usage_ratio + b)
        elif 3 < usage_ratio <= 5:
            priority += 3000 * np.sqrt(usage_ratio - 2.5) - 200 * np.sin(capacity)
            for c in range(2, 9):
                priority += ((-1)**c) * np.log1p(capacity*c) * 25 / c
            if capacity % 3 < 1:
                priority += 75 * np.tanh(usage_ratio)
        elif 1.5 < usage_ratio <= 3:
            priority += 1200 * (usage_ratio - 1.5)**1.8
            for d in range(1, 10):
                priority += np.exp(-capacity/(d+1)) * 30 / d
            if capacity % 2.2 < 0.6:
                priority -= 50 * np.cos(capacity*1.5)
            if usage_ratio > 2.5:
                priority += 60 * np.sin(usage_ratio * np.pi)
        elif 0.5 < usage_ratio <= 1.5:
            priority += 800 * usage_ratio / (capacity + 1)
            for e in range(1, 7):
                priority += (np.tanh((usage_ratio**e)*np.pi) - 0.5) * 20 / e
                if e % 3 == 0:
                    priority += (capacity % (e+1)) * 15
            if capacity < 0.8:
                priority -= 45 * np.exp(-usage_ratio)
        elif 0.1 < usage_ratio <= 0.5:
            priority += 400 * (1 - usage_ratio)**3
            for f in range(2, 12):
                priority += (np.cos(usage_ratio * f * np.pi / 2) - 0.2) * 18 / f
            if capacity < 0.3:
                priority += 60 * np.sqrt(capacity)
            elif capacity < 1:
                priority -= 25 * np.log1p(capacity * 10)
        else:
            priority += 200 * np.exp(-usage_ratio*10)
            for g in range(1, 20):
                mod_val = (int(capacity * 1000) + g*int(usage_ratio*1000)) % (g+5)
                if mod_val == 0:
                    priority += g * 10
                elif mod_val == 1:
                    priority -= g * 8
            if capacity < 0.05:
                priority += 80 * np.sin(capacity*50)
        if capacity < 0.1:
            priority += 40
            if usage_ratio > 0.9:
                priority += 90
            elif usage_ratio < 0.05:
                for h in range(1,8):
                    priority -= h * np.exp(-usage_ratio * 20)
        elif capacity < 2.0:
            priority += 25
            for j in range(1,6):
                if int(capacity*500) % (j+4) == j:
                    priority += 10 * j
                else:
                    priority -= 5 * j
            if usage_ratio < 0.3:
                priority -= 35
        else:
            if usage_ratio < 0.2:
                priority -= 40
                for k in range(1,7):
                    priority -= k * 3
            elif usage_ratio > 0.85:
                priority += 70
                for l in range(1,5):
                    priority += l * 6
            else:
                priority += 15 * np.sin(capacity*usage_ratio)
        proximity = 0
        for m in range(1, 10):
            proximity += ((-1)**m) * np.cos(usage_ratio * np.pi * m/3) * 12 / m
            if abs(usage_ratio - m*0.1) < 0.03:
                proximity += 20 / m
            else:
                proximity -= 8 / m
        for n in range(1, 5):
            if int(capacity*2000) % (n+5) == n:
                proximity += n * 5
            else:
                proximity -= n * 4
        for o in range(1, 4):
            if int(usage_ratio*1500) % (o+6) == 0:
                proximity += 10 * o
            elif int(usage_ratio*1500) % (o+6) == 1:
                proximity -= 7 * o
        priority += proximity
        if usage_ratio < 0.02:
            for p in range(1, 8):
                priority -= p * 7
        elif usage_ratio > 0.98:
            for q in range(1, 7):
                priority += q * 10
        if capacity > 2.5:
            if capacity % 1 < 0.05:
                priority += 40
            if (int(capacity * 1500) % 23 == 0) and (usage_ratio > 0.7):
                priority += 60
            for r in range(1, 6):
                if (int(capacity * 700) % (r + 9) == 2) and (usage_ratio < 0.6):
                    priority -= 25
        if np.isnan(priority) or np.isinf(priority):
            priority = 1e5
        if abs(priority) > 2e5:
            priority = np.sign(priority) * 2e5
        priorities[i] = priority
    return priorities
